---@return boolean 是否 无限
function LxBadgeCtrl:CheckBadgeWearInfinite(starRefId)
    local wearNum = LxDataHelper.GetBadgeStarWearNum(starRefId)
    return wearNum and wearNum == -1 or false
end




function LxBadgeCtrl:ParsePositionOpenStr(str)
    str = string.split(str,"=")
    local openType = checknumber(str[1])
    local openCondition = checknumber(str[2])
    local openStr = ""
    if openType == PositionOpenTypeEnum.HeroStar then
        --- 1=英雄星级：指英雄星级>=配置值时开启
        openStr = string.replace(I18nText(7803),openCondition)
    elseif openType == PositionOpenTypeEnum.RecyclingGrade then
        --- 2=回收阶级：指锦囊回收阶级>=配置值时开启
        openStr = string.replace(I18nText(7804),openCondition)
    end
    return {
        openType = openType,
        openCondition = openCondition,
        openStr = openStr,
    }
end

