---@param heroObj LxHeroObj
function LxBadgeCtrl:GetHeroBadgeShowList(heroObj)
    local heroWearBadgeMap = self:GetWearBadgeMap(heroObj)
    local star = heroObj.star
    local recyclingGrade = ModuleCenter.Badge:GetBadgeRecyclingGrade()
    local initBadgePositionList = self:GetBadgePositionRef()
    local list = {}
    local isLock = false
    local isPosWear = false
    local refId
    local openInfo,openType,openCondition
    local badgeObj
    for i,v in ipairs(initBadgePositionList) do
        refId = v.refId
        openInfo = v.openInfo
        openType = openInfo.openType
        openCondition = openInfo.openCondition
        isLock = false
        if openType == PositionOpenTypeEnum.HeroStar then
            isLock = star < openCondition
        elseif openType == PositionOpenTypeEnum.RecyclingGrade then
            isLock = recyclingGrade < openCondition
        end
        badgeObj = heroWearBadgeMap[refId]
        isPosWear = badgeObj ~= nil
        table.insert(list,{
            refId = refId,
            name = v.name,
            openInfo = openInfo,
            openStr = openInfo.openStr,
            isLock = isLock,
            badgeObj = badgeObj,
            isPosWear = isPosWear,
        })
    end
    return list
end




---@param heroObj LxHeroObj
---@return table<number,LxBadgeObj> 返回当前英雄穿戴的徽章数据 pos -> badgeObj
function LxBadgeCtrl:GetWearBadgeMap(heroObj)
    local wearBadgeMap = {}
    local badgePositions = heroObj.badgePositions
    for k,v in pairs(badgePositions) do
        wearBadgeMap[v.position] = v.badge
    end
    return wearBadgeMap
end


---@param heroObj LxHeroObj
function LxBadgeCtrl:GetCanDressBadgeList(heroObj,params)
    params = params or {}

    local heroId = heroObj.id

    ---@type number 品质，默认0：全部
    local quality = params.quality or 0
    local curPos = params.curPos or 1

    ---@type table<number,LxBadgeObj> 所有徽章数据
    local badges = ModuleCenter.Badge:GetBadges() or {}

    local list = {}
    ---@type LxBadgeDressObj
    local badgeDressObj
    local isSel,isCurPos
    local bquality
    for badgeRefId,badgeObj in pairs(badges) do
        bquality = LxDataHelper.GetBadgeQuality(badgeRefId)
        if quality == 0 or bquality == quality then
            badgeDressObj = badgeObj.heroDressObjs[heroId]
            isSel = badgeDressObj ~= nil
            isCurPos = isSel and badgeDressObj.position == curPos or false
            table.insert(list,{
                refId = badgeRefId,
                badgeObj = badgeObj,
                isSel = isSel,
                isCurPos = isCurPos,
                showWear = not isSel and not isCurPos,
                isFull = badgeObj.isWearFull,
                wearPos = curPos,
            })
        end
    end
    table.sort(list,function(a,b)
        local curPosStateA = a.isCurPos and 1 or 0
        local curPosStateB = b.isCurPos and 1 or 0
        if curPosStateA ~= curPosStateB then return curPosStateA > curPosStateB end
        local showWearStateA = a.showWear and 1 or 0
        local showWearStateB = b.showWear and 1 or 0
        if showWearStateA ~= showWearStateB then return showWearStateA > showWearStateB end
        local isSelStateA = a.isSel and 1 or 0
        local isSelStateB = b.isSel and 1 or 0
        if isSelStateA ~= isSelStateB then return isSelStateA > isSelStateB end
        return a.refId > b.refId
    end)
    return list
end



