---@param heroObj LxHeroObj 徽章一键穿戴，服务端做，函数不使用
function LxBadgeCtrl:GetAutoDressBadge(heroObj)
    local wearBadgeMap = self:GetWearBadgeMap(heroObj)

    local canWearList = {}
    local badges = ModuleCenter.Badge:GetBadges() or {}
    for k,v in pairs(badges) do
        --- 无限制 或 未穿戴满
        if v.unlimited or not v.isWearFull then
            table.insert(canWearList,{
                badgeObj = v,
                type = 1,
            })
        end
    end

    local oldWearNum = 0
    for k,v in pairs(wearBadgeMap) do
        oldWearNum = oldWearNum + 1
        table.insert(canWearList,{
            badgeObj = v,
            type = 2,
        })
    end

    table.sort(canWearList,function (a,b)
        local badgeObjA,badgeObjB = a.badgeObj,b.badgeObj
        local qualityA = LxDataHelper.GetBadgeQuality(badgeObjA.refId)
        local qualityB = LxDataHelper.GetBadgeQuality(badgeObjB.refId)
        if qualityA ~= qualityB then
            return qualityA > qualityB
        end
        local starA = LxDataHelper.GetBadgeStarNum(badgeObjA.starRefId)
        local starB = LxDataHelper.GetBadgeStarNum(badgeObjB.starRefId)
        if starA ~= starB then
            return starA > starB
        end
        return badgeObjA.refId > badgeObjB.refId
    end)

    local wearList = {}
    local star = heroObj.star
    local recyclingGrade = ModuleCenter.Badge:GetBadgeRecyclingGrade()

    local newWearMap = {}
    local wearIdx = 1
    local data

    ---@type LxBadgeObj
    local tBadgeObj

    ---@type LxBadgeObj
    local oldWearBadgeObj
    local posRefId
    local openInfo,openType,openCondition,isLock
    local samePosWear = false
    local initBadgePositionList = self:GetBadgePositionRef()
    for i,v in ipairs(initBadgePositionList) do
        openInfo = v.openInfo
        openType = openInfo.openType
        openCondition = openInfo.openCondition
        isLock = false
        if openType == PositionOpenTypeEnum.HeroStar then
            isLock = star < openCondition
        elseif openType == PositionOpenTypeEnum.RecyclingGrade then
            isLock = recyclingGrade < openCondition
        end
        if not isLock then
            data = canWearList[wearIdx]
            if data then
                posRefId = v.refId
                tBadgeObj = data.badgeObj
                samePosWear = false

                oldWearBadgeObj = wearBadgeMap[posRefId]
                if oldWearBadgeObj and oldWearBadgeObj.refId == tBadgeObj.refId then
                    samePosWear = true
                end

                if not samePosWear then
                    table.insert(wearList,{
                        badgeObj = tBadgeObj,
                        position = posRefId
                    })
                    wearIdx = wearIdx + 1
                    newWearMap[posRefId] = tBadgeObj.refId
                end
            end
        end
    end
    return wearList
end


