---@param badgeStarRef V_BadgeStarRef
function LxBadgeCtrl:GetBadgeStarNextCostSpecial(badgeStarRef)
    if not self._parseBSRefNextCostSpecialMap then
        self._parseBSRefNextCostSpecialMap = {}
    end
    local starId = badgeStarRef.refId
    local parseBSRefNextCostSpecial = self._parseBSRefNextCostSpecialMap[starId]
    if not parseBSRefNextCostSpecial then
        local ref = LxDataHelper.GetBadgeStarRef(starId)
        if ref then
            local nextCostSpecial = ref.nextCostSpecial
            if nextCostSpecial and #nextCostSpecial > 0 then
                parseBSRefNextCostSpecial = {}
                for i,v in ipairs(nextCostSpecial) do
                    v = string.split(v,"=")
                    table.insert(parseBSRefNextCostSpecial,{
                        badgeQuality = checknumber(v[1]),
                        payNum = checknumber(v[2]),
                    })
                end
                self._parseBSRefNextCostSpecialMap[starId] = parseBSRefNextCostSpecial
            end
        end
    end
    return parseBSRefNextCostSpecial
end



--- 可激活 > 可升星 > 已激活 & 不可升星 > 已激活 & 已满星 > 不可激活
function LxBadgeCtrl:GetBadgeOptList(params)
    params = params or {}
    local quality = params.quality or 0

    local resultList = {}
    ---@type table<number,LxBadgeObj> 所有徽章数据
    local badges = ModuleCenter.Badge:GetBadges() or {}
    local initBadgeRefList = self:GetInitBadgeRefList()

    ---@type V_BadgeStarRef
    local badgeStarRef
    local starRefId,star,wearNum,nextWearNum
    local itemModule = ModuleCenter.Item
    local badgeRefId,itemRefId,activateCost
    local nextCostBase,nextCostSpecial
    local payItemList = {}
    ---@type LxBadgeObj
    local badgeObj
    local isHas,isAct,isUpStar,isFullStar
    local badgeQuality,payNum
    for i,v in ipairs(initBadgeRefList) do
        badgeRefId = v.refId
        if quality == 0 or quality == LxDataHelper.GetBadgeQuality(badgeRefId) then
            itemRefId = v.itemRefId
            activateCost = v.activateCost
            badgeObj = badges[badgeRefId]
            isHas = badgeObj ~= nil
            isAct = false
            isUpStar = false
            isFullStar = false
            badgeStarRef = nil
            payItemList = {}
            wearNum = 0
            nextWearNum = 0
            star = 0
            if isHas then
                starRefId = badgeObj.starRefId
                wearNum = LxDataHelper.GetBadgeStarWearNum(starRefId)
                isFullStar = LxDataHelper.CheckBadgeIsFullStar(starRefId)
                badgeStarRef = LxDataHelper.GetBadgeStarRef(starRefId)
                if badgeStarRef then
                    star = badgeStarRef.star
                    if not isFullStar then
                        local upStarState = 0
                        local allUpStarNum = 0
                        nextWearNum = LxDataHelper.GetBadgeStarWearNum(badgeStarRef.nextStar)
                        nextCostBase = badgeStarRef.nextCostBase
                        if nextCostBase and nextCostBase > 0 then
                            table.insert(payItemList,{
                                --- 道具消耗
                                selType = 0,
                                type = ThingType.Item,
                                refId = itemRefId,
                                num = nextCostBase,
                            })
                            if itemModule:GetItemCount(itemRefId) >= nextCostBase then
                                upStarState = upStarState + 1
                            end
                            allUpStarNum = allUpStarNum + 1
                        end
                        nextCostSpecial = self:GetBadgeStarNextCostSpecial(badgeStarRef)
                        if nextCostSpecial and #nextCostSpecial > 0 then
                            local isCanUpStar = true
                            for idx,val in ipairs(nextCostSpecial) do
                                badgeQuality,payNum = val.badgeQuality,val.payNum
                                if isCanUpStar then
                                    isCanUpStar = self:CalcQualityBadgeHasNum(badgeQuality) >= payNum
                                end
                                table.insert(payItemList,{
                                    --- 打开界面选择
                                    selType = 1,
                                    badgeQuality = badgeQuality,
                                    payNum = payNum,
                                })
                            end
                            if isCanUpStar then
                                upStarState = upStarState + 1
                            end
                            allUpStarNum = allUpStarNum + 1
                        end
                        isUpStar = upStarState >= allUpStarNum
                    end
                end
            else
                isAct = itemModule:GetItemCount(itemRefId) >= activateCost
                star = 0
                starRefId = LxDataHelper.GetBadgeStarRefId(badgeRefId,star)
                badgeStarRef = LxDataHelper.GetBadgeStarRef(starRefId)
                if badgeStarRef then
                    nextWearNum = badgeStarRef.wearNum
                    nextCostBase = badgeStarRef.nextCostBase
                    if nextCostBase and nextCostBase > 0 then
                        table.insert(payItemList,{
                            --- 道具消耗
                            selType = 0,
                            type = ThingType.Item,
                            refId = itemRefId,
                            num = nextCostBase,
                        })
                    end
                    nextCostSpecial = self:GetBadgeStarNextCostSpecial(badgeStarRef)
                    if nextCostSpecial and #nextCostSpecial > 0 then
                        local isCanUpStar = true
                        for idx,val in ipairs(nextCostSpecial) do
                            badgeQuality,payNum = val.badgeQuality,val.payNum
                            if isCanUpStar then
                                isCanUpStar = self:CalcQualityBadgeHasNum(badgeQuality) >= payNum
                            end
                            table.insert(payItemList,{
                                --- 打开界面选择
                                selType = 1,
                                badgeQuality = badgeQuality,
                                payNum = payNum,
                            })
                        end
                        isUpStar = isCanUpStar
                    end
                end
            end
            table.insert(resultList,{
                refId = badgeRefId,
                name = v.name,
                quality = v.quality,
                icon = v.icon,
                sort = v.sort,
                collectType = v.collectType,
                itemRefId = itemRefId,
                activateCost = activateCost,
                starRefId = starRefId,
                badgeObj = badgeObj,
                payItemList = payItemList,
                isAct = isAct,
                isHas = isHas,
                isUpStar = isUpStar,
                isFullStar = isFullStar,
                star = star,
                wearNum = wearNum,
                nextWearNum = nextWearNum,
            })
        end
    end

    --- 可激活 > 可升星 > 已激活 & 不可升星 > 已激活 & 已满星 > 不可激活
    table.sort(resultList,function(a,b)
        local actStateA = a.isAct and 1 or 0
        local actStateB = b.isAct and 1 or 0
        if actStateA ~= actStateB then return actStateA > actStateB end
        local upStarStateA = a.isUpStar and 1 or 0
        local upStarStateB = b.isUpStar and 1 or 0
        if upStarStateA ~= upStarStateB then return upStarStateA > upStarStateB end
        local hasStateA = a.isHas and 1 or 0
        local hasStateB = b.isHas and 1 or 0
        if hasStateA ~= hasStateB then return hasStateA > hasStateB end
        local fullStarA = a.isFullStar and 1 or 0
        local fullStarB = b.isFullStar and 1 or 0
        if fullStarA ~= fullStarB then return fullStarA < fullStarB end
        local qualityA = a.quality
        local qualityB = b.quality
        if qualityA ~= qualityB then return qualityA > qualityB end
        return actStateA < actStateB
    end)

    return resultList
end




function LxBadgeCtrl:GetQualityBadgeNeedItemList(quality)
    local badgeQualityItemRefIdMap = self:GetBadgeQualityItemRefIdMap()
    return badgeQualityItemRefIdMap[quality] or {}
end



function LxBadgeCtrl:CalcQualityBadgeHasNum(quality)
    local badgeQualityItemRefIds = self:GetQualityBadgeNeedItemList(quality)
    if not badgeQualityItemRefIds or #badgeQualityItemRefIds < 1 then return 0 end

    local itemModule = ModuleCenter.Item
    local calcNum = 0
    for i,info in ipairs(badgeQualityItemRefIds) do
        calcNum = calcNum + itemModule:GetItemCount(info.itemRefId)
    end
    return calcNum
end


function LxBadgeCtrl:GetQualityOptItemList(quality)
    local badgeQualityItemRefIds = self:GetQualityBadgeNeedItemList(quality)
    if not badgeQualityItemRefIds or #badgeQualityItemRefIds < 1 then
        return {}
    end
    local list = {}

    local badgeModule = ModuleCenter.Badge
    local badgeRefId
    ---@type LxBadgeObj
    local badgeObj
    local isFullStar
    for i,v in ipairs(badgeQualityItemRefIds) do
        isFullStar = false
        badgeRefId = v.badgeRefId
        badgeObj = badgeModule:GetBadge(badgeRefId)
        if badgeObj and LxDataHelper.CheckBadgeIsFullStar(badgeObj.starRefId) then
            isFullStar = true
        end
        table.insert(list,{
            badgeRefId = badgeRefId,
            itemRefId = v.itemRefId,
            sort = v.sort,
            isFullStar = isFullStar,
        })
    end
    table.sort(list,function(a,b)
        local fullStateA = a.isFullStar and 1 or 0
        local fullStateB = b.isFullStar and 1 or 0
        if fullStateA ~= fullStateB then return fullStateA > fullStateB end
        return a.itemRefId < b.itemRefId
    end)
    return list
end



