function LxBadgeCtrl:GetBadgePositionOpenGrade()
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return -1 end

    local recyclingGrade = badgeRecyclingObj.grade
    local openInfo
    local initBadgePositionList = self:GetBadgePositionRef()
    for i,v in ipairs(initBadgePositionList) do
        openInfo = v.openInfo
        if openInfo and
                openInfo.openType == PositionOpenTypeEnum.RecyclingGrade and
                openInfo.openCondition > recyclingGrade then
            return openInfo.openCondition
        end
    end
    return -1
end

