---@return boolean 是否可升阶
function LxBadgeCtrl:CheckBadgeRecycleCanUpGrade()
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local grade = badgeRecyclingObj.grade
    local ref = self:GetInitBadgeRecoverRankRef(grade)
    if not ref then return false end

    if ref.needLv == -1 then return false end

    return badgeRecyclingObj.level >= ref.needLv
end


function LxBadgeCtrl:CheckBadgeRecycleCanUpLevel()
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local level = badgeRecyclingObj.level
    local ref = self:GetInitBadgeRecoverLvRefByRefId(level)
    if not ref then return false end

    if ref.cost1 > badgeRecyclingObj.blueCnt then return false end
    if ref.cost2 > badgeRecyclingObj.purpleCnt then return false end
    if ref.cost3 > badgeRecyclingObj.orangeCnt then return false end

    if ref.nextLv == -1 then return false end

    local nextLvCost = ref.nextLvCost
    if #nextLvCost < 1 then return false end

    return CtrlCenter.Item:CheckItemListEnough(nextLvCost)
end


function LxBadgeCtrl:GetBadgeRecycleItemList(quality)
    local resultList = {}
    ---@type LxBadgeObj
    local badgeObj
    local badgeRefId,itemRefId
    local itemModule = ModuleCenter.Item
    ---@type table<number,LxBadgeObj> 所有徽章数据
    local badges = ModuleCenter.Badge:GetBadges() or {}
    local initBadgeRefList = self:GetInitBadgeRefList()
    for i,v in ipairs(initBadgeRefList) do
        badgeRefId = v.refId
        if quality == LxDataHelper.GetBadgeQuality(badgeRefId) then
            badgeObj = badges[badgeRefId]
            if badgeObj and LxDataHelper.CheckBadgeIsFullStar(badgeObj.starRefId) then
                itemRefId = v.itemRefId
                table.insert(resultList,{
                    itemRefId = itemRefId,
                    hasNum  = itemModule:GetItemCount(itemRefId),
                })
            end
        end
    end
    return resultList
end


--- 红点检测，是否可以激活或者升星
function LxBadgeCtrl:CheckBadgeCanActOrUpStar()
    local list = self:GetBadgeOptList()
    for i,v in ipairs(list) do
        if v.isAct or v.isUpStar then return true end
    end
    return false
end

--- 红点检测，是否可以回收升级或进阶，可投放品质也算
function LxBadgeCtrl:CheckBadgeCanRecycleUpLevelOrGrade()
    if not self:CheckIsFullBadgePutInRecycle() then return false end

    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local curLevel = badgeRecyclingObj.level
    local maxLevel = self:GetBadgeRecoverMaxLv()
    if curLevel >= maxLevel then
        if self:CheckBadgeCanRecycleGradeRP() then return true end
        return false
    end

    local isUpGrade = self:CheckBadgeRecycleCanUpGrade()
    if isUpGrade then
        return self:CheckBadgeCanRecycleGradeRP()
    else
        if self:CheckBadgeCanRecycleUpLevelRP() then return true end

        return self:CheckIsFullBadgeRecycleExpendQuality(0)
    end
end

--- 投放的数量
function LxBadgeCtrl:CheckIsFullBadgePutInRecycle()
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local curLevel = badgeRecyclingObj.level
    local maxLevel = self:GetBadgeRecoverMaxLv()
    if curLevel >= maxLevel then return false end

    local curLevelRef = self:GetInitBadgeRecoverLvRefByRefId(curLevel)
    if not curLevelRef then return false end

    local loseNum1 = curLevelRef.cost1 - badgeRecyclingObj.blueCnt
    local loseNum2 = curLevelRef.cost2 - badgeRecyclingObj.purpleCnt
    local loseNum3 = curLevelRef.cost3 - badgeRecyclingObj.orangeCnt
    return loseNum1 < 1 and loseNum2 < 1 and loseNum3 < 1
end

function LxBadgeCtrl:CheckBadgeCanRecycleUpLevelRP()
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local curLevel = badgeRecyclingObj.level
    local maxLevel = self:GetBadgeRecoverMaxLv()
    if curLevel >= maxLevel then return false end

    local curLevelRef = self:GetInitBadgeRecoverLvRefByRefId(curLevel)
    if not curLevelRef then return false end

    if CtrlCenter.Item:CheckItemListEnough(curLevelRef.nextLvCost) then return true end
end

function LxBadgeCtrl:CheckBadgeCanRecycleGradeRP()
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local curRankRef = self:GetInitBadgeRecoverRankRef(badgeRecyclingObj.grade)
    if not curRankRef then return false end

    if curRankRef.nextLv < 1 then return false end

    return CtrlCenter.Item:CheckItemListEnough(curRankRef.cost)
end

function LxBadgeCtrl:CheckIsFullBadgeRecycleExpendQuality(quality)
    local badgeRecyclingObj = ModuleCenter.Badge:GetBadgeRecyclingObj()
    if not badgeRecyclingObj then return false end

    local curLevel = badgeRecyclingObj.level
    local maxLevel = self:GetBadgeRecoverMaxLv()
    if curLevel >= maxLevel then return false end

    local curLevelRef = self:GetInitBadgeRecoverLvRefByRefId(curLevel)
    if not curLevelRef then return false end

    local loseNum1 = curLevelRef.cost1 - badgeRecyclingObj.blueCnt
    local loseNum2 = curLevelRef.cost2 - badgeRecyclingObj.purpleCnt
    local loseNum3 = curLevelRef.cost3 - badgeRecyclingObj.orangeCnt

    local loseNumFull1 = loseNum1 < 1
    local loseNumFull2 = loseNum2 < 1
    local loseNumFull3 = loseNum3 < 1

    if loseNumFull1 and loseNumFull2 and loseNumFull3 then return false end

    local badgeQuality
    quality = quality or 0
    ---@type table<number,LxBadgeObj> 所有徽章数据
    local badges = ModuleCenter.Badge:GetBadges() or {}
    local itemRefId,hasNum
    for k,v in pairs(badges) do
        badgeQuality = LxDataHelper.GetBadgeQuality(v.refId)
        if quality == 0 or quality == badgeQuality then
            if LxDataHelper.CheckBadgeIsFullStar(v.starRefId) then
                local isCheck = false
                if not loseNumFull1 and badgeQuality == 3 then
                    isCheck = true
                elseif not loseNumFull2 and badgeQuality == 4 then
                    isCheck = true
                elseif not loseNumFull3 and badgeQuality == 5 then
                    isCheck = true
                end
                if isCheck then
                    itemRefId = LxDataHelper.GetBadgeItemRefId(v.refId)
                    hasNum = itemRefId and ModuleCenter.Item:GetItemCount(itemRefId) or 0
                    if hasNum > 0 then
                        if badgeQuality == 3 and hasNum - loseNum1 >= 0 then
                            return true
                        elseif badgeQuality == 4 and hasNum - loseNum2 >= 0 then
                            return true
                        elseif badgeQuality == 5 and hasNum - loseNum3 >= 0 then
                            return true
                        end
                    end
                end
            end
        end
    end
end


