function LxBadgeCtrl:GetCollectTypeBadgeSchedule(collectType)
    local schedule = 0
    local badges = ModuleCenter.Badge:GetBadges()
    for k,v in pairs(badges) do
        if LxDataHelper.GetBadgeCollectType(k) == collectType then
            schedule = schedule + LxDataHelper.GetBadgeStarNum(v.starRefId) + 1
        end
    end
    return schedule
end

function LxBadgeCtrl:CheckBadgeCollectTypeIsAct(collectType)
    local schedule = self:GetCollectTypeBadgeSchedule(collectType)
    local collectObj = ModuleCenter.Badge:GetCollectObj(collectType)
    if not collectObj then
        --- 未激活时
        return schedule > 0
    end
    local collectRefs = self:GetInitBadgeCollectRefListByCollectType(collectType)
    if not collectRefs or #collectRefs < 1 then return false end

    if #collectRefs < schedule then return false end

    return schedule > collectObj.count
end

--- 共鸣红点
function LxBadgeCtrl:CheckBadgeCollectRP()
    local initBadgeCollectRefList = self:GetInitBadgeCollectRefList()
    for collectType,refs in pairs(initBadgeCollectRefList) do
        if self:CheckBadgeCollectTypeIsAct(collectType) then
            return true
        end
    end
    return false
end

