--- 是否可以一键装配
---@param heroObj LxHeroObj
function LxBadgeCtrl:CheckHasBadgeFitting(heroObj)
    local badgePositions = heroObj.badgePositions
    local wearBadgeRefIdMap = {}
    for k,v in pairs(badgePositions) do
        wearBadgeRefIdMap[v.badge.refId] = true
    end

    local canFittingBadges = {}
    local badges = ModuleCenter.Badge:GetBadges()
    for k,v in pairs(badges) do
        if not v.isWearFull and not wearBadgeRefIdMap[v.refId] then
            table.insert(canFittingBadges,v)
        end
    end

    if #canFittingBadges < 1 then return false end

    local recyclingGrade = ModuleCenter.Badge:GetBadgeRecyclingGrade()
    local star = heroObj.star
    local openInfo,openType,openCondition,isOpen
    local initBadgePositionList = self:GetBadgePositionRef()
    for i,v in ipairs(initBadgePositionList) do
        if not badgePositions[v.refId] then
            openInfo = v.openInfo
            openType = openInfo.openType
            openCondition = openInfo.openCondition
            isOpen = false
            if openType == PositionOpenTypeEnum.HeroStar then
                isOpen = star >= openCondition
            elseif openType == PositionOpenTypeEnum.RecyclingGrade then
                isOpen = recyclingGrade >= openCondition
            end
            if isOpen then
                return true
            end
        end
    end
end

--- 位置是否可以装配
---@param heroObj LxHeroObj
---@param position number 位置
function LxBadgeCtrl:CheckHasBadgeFittingByPosition(heroObj,position)
    local badgePositions = heroObj.badgePositions
    if badgePositions[position] then return false end

    local wearBadgeRefIdMap = {}
    for k,v in pairs(badgePositions) do
        wearBadgeRefIdMap[v.badge.refId] = true
    end

    local canFittingBadges = {}
    local badges = ModuleCenter.Badge:GetBadges()
    for k,v in pairs(badges) do
        if not v.isWearFull and not wearBadgeRefIdMap[v.refId] then
            table.insert(canFittingBadges,v)
        end
    end

    if #canFittingBadges < 1 then return false end

    local initBadgePositionList = self:GetBadgePositionRef()
    local ref = initBadgePositionList[position]
    if not ref then return false end

    local openInfo = ref.openInfo
    local openType = openInfo.openType
    local openCondition = openInfo.openCondition
    local isOpen = false
    if openType == PositionOpenTypeEnum.HeroStar then
        isOpen = heroObj.star >= openCondition
    elseif openType == PositionOpenTypeEnum.RecyclingGrade then
        isOpen = ModuleCenter.Badge:GetBadgeRecyclingGrade() >= openCondition
    end
    return isOpen
end


return LxBadgeCtrl